{
  "name": "url-shortener",
  "main": "src/index.js",
  "compatibility_date": "2025-06-01",
  // Serve everything in ./public as static files (the HTML form lives here)
  "assets": { "directory": "./public" },
  // Make the KV namespace available in code as env.LINKS
  "kv_namespaces": [
    { "binding": "LINKS", "id": "<paste-your-id-here>" }
  ]
}

// src/index.js — the entire back-end of the URL shortener

// Build a random short code, e.g. "a8Kp2Z", from safe characters.
function makeCode(length = 6) {
  const chars =
    "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";
  const bytes = crypto.getRandomValues(new Uint8Array(length));
  let code = "";
  for (const byte of bytes) {
    code += chars[byte % chars.length];
  }
  return code;
}

export default {
  async fetch(request, env) {
    const url = new URL(request.url);

    // 1) CREATE a short link:  POST /api/shorten  with { "url": "https://..." }
    if (request.method === "POST" && url.pathname === "/api/shorten") {
      const body = await request.json();
      const longUrl = body.url;

      // Validate the input before trusting it.
      const ok =
        longUrl &&
        (longUrl.startsWith("http://") || longUrl.startsWith("https://"));
      if (!ok) {
        return Response.json(
          { error: "Please send a valid http(s) URL" },
          { status: 400 }
        );
      }

      const code = makeCode(6);
      await env.LINKS.put(code, longUrl); // save the pair: code -> long URL
      return Response.json({ short: "/" + code });
    }

    // 2) RESOLVE a short link:  GET /<code>  ->  302 redirect to the long URL
    if (request.method === "GET") {
      const code = url.pathname.slice(1); // drop the leading "/"
      const longUrl = await env.LINKS.get(code); // look the code up in KV
      if (longUrl) {
        return Response.redirect(longUrl, 302);
      }
      return new Response("Short link not found", { status: 404 });
    }

    return new Response("Method not allowed", { status: 405 });
  },
};

