CREATE TABLE links (
  code       TEXT PRIMARY KEY,
  long_url   TEXT NOT NULL,
  created_at INTEGER NOT NULL
);

CREATE TABLE clicks (
  id         INTEGER PRIMARY KEY,
  code       TEXT NOT NULL,
  clicked_at INTEGER NOT NULL
);
